class Solution {
public:
bool findIndex(std::vector<int>& nums, int n, int target) {
	int left = 0, right = n - 1;
	while (left <= right) {
		int mid = left + (right - left) / 2;
		if (nums[mid] == target) {
			return mid;
		}
		else if (nums[mid] < target) {
			left = mid + 1;
		}
		else {
			right = mid - 1;
		}
	}
	return -1;
}

int main() {
	std::vector<int> nums = {1, 2, 3, 4, 5};
	int n = 5, target = 3;
	Solution solver;
	std::cout << std::boolalpha << solver.findIndex(nums, n, target) << std::endl;
	return 0;
}
